func dealsStaleData(s *store.Store, pipelineFilter string, days, limit int, now time.Time) ([]dealsStaleRow, error) {
	stageNames, pipelines := map[string]string{}, map[string]dealsVelocityPipeline{}
	if err := loadVelocityPipelines(s, pipelineFilter, stageNames, pipelines); err != nil {
		return nil, err
	}

	cutoff := now.AddDate(0, 0, -days)
	items, err := s.List("deals", 10000)
	if err != nil {
		return nil, err
	}

	type dealRecord struct {
		ID         string            `json:"id"`
		Properties map[string]string `json:"properties"`
	}
	out := make([]dealsStaleRow, 0, len(items))
	for _, item := range items {
		var deal dealRecord
		if json.Unmarshal(item, &deal) != nil {
			continue
		}
		pid := deal.Properties["pipeline"]
		if pipelineFilter != "" && pid != pipelineFilter {
			continue
		}
		lastModified, ok := parseHubSpotTime(deal.Properties["lastmodifieddate"])
		if !ok || !lastModified.Before(cutoff) {
			continue
		}
		stageID := deal.Properties["dealstage"]
		stageName := stageNames[pid+":"+stageID]
		if stageName == "" {
			stageName = max(stageID, "Unknown")
		}
		name := deal.Properties["dealname"]
		if name == "" {
			name = max(deal.ID, "Untitled deal")
		}
		out = append(out, dealsStaleRow{
			DealName:  name,
			Stage:     stageName,
			Amount:    normalizeDealAmount(deal.Properties["amount"]),
			Owner:     max(deal.Properties["hubspot_owner_id"], "Unassigned"),
			DaysStale: int(now.Sub(lastModified).Hours() / 24),
		})
	}

	sort.Slice(out, func(i, j int) bool {
		if out[i].DaysStale != out[j].DaysStale {
			return out[i].DaysStale > out[j].DaysStale
		}
		if out[i].Stage != out[j].Stage {
			return out[i].Stage < out[j].Stage
		}
		return out[i].DealName < out[j].DealName
	})
	if limit > 0 && len(out) > limit {
		out = out[:limit]
	}
	return out, nil
}

func printDealsStaleTable(cmd *cobra.Command, rows []dealsStaleRow) error {
	tw := newTabWriter(cmd.OutOrStdout())
	fmt.Fprintln(tw, strings.Join([]string{bold("DEAL NAME"), bold("STAGE"), bold("AMOUNT"), bold("OWNER"), bold("DAYS STALE")}, "\t"))
	for _, row := range rows {
		fmt.Fprintf(tw, "%s\t%s\t%s\t%s\t%d\n", row.DealName, row.Stage, row.Amount, row.Owner, row.DaysStale)
	}
	return tw.Flush()
}

func normalizeDealAmount(v string) string {
	if v == "" {
		return ""
	}
	n, err := strconv.ParseFloat(v, 64)
	if err != nil {
		return v
	}
	return fmt.Sprintf("%.2f", n)
}
